// Flatten Outreach /sequenceSteps -> one row per step for analysis.
// Spreads ALL step attributes so we can see whether per-step engagement counters
// (open/click/reply) exist, plus the step order, type, and parent sequence id.
const out = [];
for (const item of $input.all()) {
  const body = item.json || {};
  const list = Array.isArray(body.data) ? body.data : (Array.isArray(body) ? body : [body]);
  for (const st of list) {
    if (!st || st.id == null) continue;
    const a = st.attributes || {};
    const rel = st.relationships || {};
    const seqId = rel.sequence && rel.sequence.data && rel.sequence.data.id;
    out.push({ json: Object.assign(
      { step_id: String(st.id), sequence_id: seqId != null ? String(seqId) : null },
      a) });
  }
}
if (out.length === 0) {
  throw new Error('No sequence steps returned - check the OAuth2 credential and that the token scope includes sequenceSteps.read.');
}
return out;
